import React from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const QueryAnalytics = ({ data }: { data: any }) => {
    if (!data || !data.historical_queries) return null;

    return (
        <div className="flex flex-col h-full pt-4">
            <div className="h-64 w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={data.historical_queries} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                        <XAxis
                            dataKey="time"
                            stroke="#333"
                            fontSize={10}
                            tickLine={false}
                            axisLine={false}
                            dy={10}
                        />
                        <YAxis
                            stroke="#333"
                            fontSize={10}
                            tickLine={false}
                            axisLine={false}
                        />
                        <CartesianGrid strokeDasharray="1 10" stroke="#1A1A1A" vertical={false} />
                        <Tooltip
                            contentStyle={{
                                backgroundColor: '#000',
                                border: '1px solid #2A2A2A',
                                borderRadius: '8px',
                                fontSize: '10px',
                                textTransform: 'uppercase'
                            }}
                            itemStyle={{ color: '#fff' }}
                        />
                        <Line
                            type="stepAfter"
                            dataKey="gpt4"
                            stroke="#FFFFFF"
                            strokeWidth={1}
                            dot={{ fill: '#000', stroke: '#FFFFFF', strokeWidth: 1, r: 2 }}
                            activeDot={{ r: 4, strokeWidth: 0, fill: '#FF3B30' }}
                            name="PREMIUM"
                        />
                        <Line
                            type="stepAfter"
                            dataKey="sonnet"
                            stroke="#888"
                            strokeWidth={1}
                            dot={{ fill: '#000', stroke: '#888', strokeWidth: 1, r: 2 }}
                            name="BALANCED"
                        />
                        <Line
                            type="stepAfter"
                            dataKey="phi3_local"
                            stroke="#333"
                            strokeWidth={1}
                            dot={{ fill: '#000', stroke: '#333', strokeWidth: 1, r: 2 }}
                            name="LOCAL"
                        />
                    </LineChart>
                </ResponsiveContainer>
            </div>

            {/* Model Legend Dots */}
            <div className="mt-6 flex space-x-6 justify-center">
                <div className="flex items-center space-x-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-white shadow-[0_0_5px_rgba(255,255,255,0.5)]" />
                    <span className="nothing-text-label text-white">PHI-3-PREMIUM</span>
                </div>
                <div className="flex items-center space-x-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-gray-500" />
                    <span className="nothing-text-label">PHI-3-BALANCED</span>
                </div>
                <div className="flex items-center space-x-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-gray-800" />
                    <span className="nothing-text-label">PHI-3-LOCAL</span>
                </div>
            </div>
        </div>
    );
};

export default QueryAnalytics;
